frappe.ui.form.on("Job Requisition Form", {
    workflow_state: function(frm) {
        if (frm.doc.workflow_state === "Approved by Managing Director" 
            && frm.doc.status !== "Open & Approved") {

            frappe.confirm(
                "Do you want to change Status to <b>Open & Approved</b>?",
                function () {
                    frm.set_value("status", "Open & Approved");
                    frm.save();
                },
                function () {
                    frappe.msgprint("Please update the Status field manually.");
                }
            );
        }
    }
});

frappe.ui.form.on("Variable Pay Disbursement", {
    refresh: function(frm) {
        frm.set_query("employee", function() {
            return {
                filters: {
                    custom_variable_amount: ["!=", ""]
                }
            };
        });
    }
});
frappe.ui.form.on("Variable Pay Disbursement", {
    employee(frm) {
        if (frm.doc.employee) {
            frappe.db.get_value("Employee", frm.doc.employee, "date_of_joining")
                .then(r => {
                    if (r.message.date_of_joining) {
                        let doj = frappe.datetime.str_to_obj(r.message.date_of_joining);
                        let disburse_date = frappe.datetime.add_months(doj, 3);
                        frm.set_value("disburse_date", frappe.datetime.obj_to_str(disburse_date));
                    }
                });
        }
    }
});

frappe.ui.form.on('Payroll Entry', {
    refresh: function(frm) {
        frm.fields_dict['employees'].grid.get_field('employee').get_query = function(doc, cdt, cdn) {
            // Add 15 days to start_date
            let end_date = frm.doc.start_date 
                ? frappe.datetime.add_days(frm.doc.start_date, 14) 
                : null;

            return {
                filters: [
                    ["status", "=", "Active"],
                    ["date_of_joining", "<", end_date]
                ]
            };
        };
    }
});

frappe.ui.form.on('Leave Encashment', {
    employee(frm) {
        if (!frm.doc.employee) {
            frm.set_value('custom_leave_encashment_amount_per_day', 0);
            frm.set_value('encashment_amount', 0);
            frm.set_value('custom_used_leave', 0);
            return;
        }

        // 1) Fetch per-day encashment rate (API)
        frappe.call({
            method: "get_basic_salary",
            args: { employee: frm.doc.employee },
            callback(r) {
                const per_day = parseFloat(r.message) || 0;
                frm.set_value('custom_leave_encashment_amount_per_day', per_day);

                // Live preview (final value will still be set by server on save)
                preview_encashment_amount(frm);
            }
        });

        // 2) Fetch used Earned Leave (Approved only)
        frappe.call({
            method: "get_used_leaves",
            args: { employee: frm.doc.employee },
            callback(r) {
                frm.set_value('custom_used_leave', parseFloat(r.message) || 0);
            }
        });
    },

    // Live preview when leave balance changes
    leave_balance(frm) {
        preview_encashment_amount(frm);
    },

    // Live preview when per-day rate changes
    custom_leave_encashment_amount_per_day(frm) {
        preview_encashment_amount(frm);
    }
});

// ------------------------------
// Helper (UI-only preview)
// ------------------------------
function preview_encashment_amount(frm) {
    const per_day = parseFloat(frm.doc.custom_leave_encashment_amount_per_day) || 0;
    const balance = parseFloat(frm.doc.leave_balance) || 0;

    if (!per_day || !balance) {
        frm.set_value('encashment_amount', 0);
        return;
    }

    // NOTE:
    // Exact business rules (Active vs Exited, 60:40 / 50:50)
    // are enforced SERVER-SIDE.
    // Here we only provide a rough live preview.

    let preview_days = balance >= 9 ? balance * 0.4 : balance * 0.5;
    frm.set_value('encashment_amount', per_day * preview_days);
}

frappe.ui.form.on('Salary Slip', {
    refresh(frm) {
        apply_hard_rounding(frm, 'earnings');
        apply_hard_rounding(frm, 'deductions');
    }
});

function apply_hard_rounding(frm, table_fieldname) {
    const grid = frm.fields_dict[table_fieldname].grid;

    // This overrides the specific display function for this grid
    grid.get_docfield("amount").get_display = function(value) {
        if (value || value === 0) {
            // 1. Convert to float and round up (Math.ceil)
            let rounded_val = Math.ceil(flt(value));

            // 2. Format with currency symbol and 0 decimals
            let formatted = format_currency(rounded_val, frm.doc.currency, 0);

            // 3. Return the exact HTML structure your grid is looking for
            return `<div style="text-align: right; font-weight: 600; color: #2563eb;">${formatted}</div>`;
        }
        return value;
    };

    // Force the grid to rebuild the visible columns with the new display function
    grid.visible_columns = undefined;
    grid.setup_visible_columns();
    grid.refresh();
}

