function add_days(date_str, days) {
    if (!date_str || days === '' || days === null) return null;
    let d = frappe.datetime.str_to_obj(date_str);
    d.setDate(d.getDate() + parseInt(days));
    return frappe.datetime.obj_to_str(d);
}

function diff_days(start_str, end_str) {
    if (!start_str || !end_str) return null;
    let start = frappe.datetime.str_to_obj(start_str);
    let end = frappe.datetime.str_to_obj(end_str);
    return Math.round((end - start) / (1000 * 60 * 60 * 24));
}

frappe.ui.form.on('Employee Resignation', {

    // ✅ NEW: Onload logic
    onload(frm) {
        if (frm.is_new()) {

            // 👉 Set default resignation date = today
            frm.set_value('resignation_date', frappe.datetime.get_today());

            // 👉 Auto fetch employee based on logged-in user
            let user = frappe.session.user;

            if (user && user !== "Administrator") {
                frappe.db.get_value('Employee', { user_id: user }, 'name')
                    .then(r => {
                        if (r.message && r.message.name) {
                            frm.set_value('employee', r.message.name);
                            frm.trigger('employee'); // existing logic trigger
                        }
                    });
            }
        }
    },

    employee(frm) {
        if (!frm.doc.employee) {
            frm.set_value('employee_name', '');
            frm.set_value('designation', '');
            frm.set_value('reporting_manager', '');
            frm.set_value('notice_period_as_per_policy', '');
            return;
        }

        frappe.db.get_value('Employee', frm.doc.employee,
            ['employee_name', 'designation', 'custom_reporting_manager', 'notice_number_of_days'],
            (data) => {
                if (!data) return;

                frm.set_value('employee_name', data.employee_name);
                frm.set_value('designation', data.designation);
                frm.set_value('reporting_manager', data.custom_reporting_manager);
                frm.set_value('notice_period_as_per_policy', data.notice_number_of_days);

                frm.trigger('calc_reliving_date');
                frm.trigger('calc_serving_days_left');
            }
        );
    },

    resignation_date(frm) {
        frm.trigger('calc_reliving_date');
    },

    notice_period_as_per_policy(frm) {
        frm.trigger('calc_reliving_date');
        frm.trigger('calc_serving_days_left');
    },

    notice_period_start_date(frm) {
        frm.trigger('calc_serving_days_left');
    },

    confirmed_last_working_day(frm) {
        frm.trigger('calc_serving_days_left');
        frm.set_value('actual_reliving_date', frm.doc.confirmed_last_working_day || '');
    },

    calc_reliving_date(frm) {
        let result = add_days(frm.doc.resignation_date, frm.doc.notice_period_as_per_policy);
        frm.set_value('reliving_date', result || '');
    },

    calc_serving_days_left(frm) {
        let start = frm.doc.notice_period_start_date;
        let end = frm.doc.confirmed_last_working_day;

        if (start && end) {
            frm.set_value('serving_days_left', diff_days(start, end));
        } else {
            frm.set_value('serving_days_left', frm.doc.notice_period_as_per_policy || '');
        }
    }

});

frappe.ui.form.on("Employee Resignation", {
    refresh: function(frm) {

        if (frm.doc.docstatus === 1) {
            frm.add_custom_button("Initiate Separation", function() {

                if (!frm.doc.employee) {
                    frappe.msgprint("Employee not found in this resignation");
                    return;
                }

                frappe.db.get_value("Employee", frm.doc.employee,
                    ["employee_name", "designation"]
                ).then(r => {

                    let emp = r.message;

                    // Use confirmed_last_working_day if available, else fall back to proposed
                    let base_date = frm.doc.confirmed_last_working_day 
                        || frm.doc.proposed_last_working_day;

                    frappe.new_doc("Employee Separation", {
                        employee: frm.doc.employee,
                        employee_name: emp.employee_name,
                        designation: emp.designation,
                        company: "Intellinum Technologies Private Limited",
                        custom_employee_resignation: frm.doc.name,
                        boarding_begins_on: base_date
                            ? frappe.datetime.add_days(base_date, -2)
                            : ""
                    });

                });

            });
        }
    }
});

frappe.ui.form.on("Employee Separation", {
    refresh: function(frm) {

        if (frm.doc.docstatus === 1 || frm.doc.status === "Completed") {

            frm.add_custom_button(__("Create Full & Final"), function() {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "Full and Final Statement",
                        filters: { employee: frm.doc.employee },
                        fields: ["name"],
                        limit: 1
                    },
                    callback: function(r) {

                        if (r.message && r.message.length > 0) {
                            frappe.confirm(
                                "Full & Final already exists for <b>" + frm.doc.employee_name + "</b>.<br>Do you want to open it?",
                                function() {
                                    frappe.set_route("Form", "Full and Final Statement", r.message[0].name);
                                }
                            );
                            return;
                        }

                        frappe.confirm(
                            "Create Full & Final Statement for <b>" + frm.doc.employee_name + "</b>?",
                            function() {
                                frappe.call({
                                    method: "create_full_and_final",
                                    args: { separation_name: frm.doc.name },
                                    freeze: true,
                                    freeze_message: "Creating Full & Final Statement...",
                                    callback: function(r) {

                                        if (r.message) {

                                            if (r.message.status === "exists") {
                                                frappe.show_alert({
                                                    message: "Already exists: " + r.message.name,
                                                    indicator: "orange"
                                                });
                                                frappe.set_route("Form", "Full and Final Statement", r.message.name);

                                            } else if (r.message.status === "created") {
                                                frappe.show_alert({
                                                    message: "✅ Full & Final Created: " + r.message.name,
                                                    indicator: "green"
                                                });
                                                frappe.set_route("Form", "Full and Final Statement", r.message.name);
                                            }

                                        }
                                    }
                                });
                            }
                        );
                    }
                });
            });

            frm.add_custom_button(__("Resignation Acceptance Letter"), function() {
                frappe.utils.print(
                    "Employee Separation",
                    frm.doc.name,
                    "Resignation Acceptance Letter",
                    frm.doc.language || "en"
                );
            });

        }
    }
});

