frappe.ui.form.on('Employee Separation', {
    refresh: function(frm) {
        if (frm.__is_refreshing) return;
        frm.__is_refreshing = true;

        (frm.doc.activities || []).forEach(function(row) {
            if (row.task) {
                fetch_task_values(frm, row.doctype, row.name);
            }
        });

        setTimeout(() => {
            frm.__is_refreshing = false;
        }, 500);
    }
});

function fetch_task_values(frm, cdt, cdn) {

    let row = locals[cdt][cdn];
    if (!row.task) return;

    frappe.db.get_value('Task', row.task, ['status', 'custom_valuation', 'custom_remark'])
    .then(r => {

        let value = r.message;
        if (!value) return;

        let changed = false;

        if (row.status !== value.status) {
            row.status = value.status;
            changed = true;
        }

        if (row.custom_valuation !== value.custom_valuation) {
            row.custom_valuation = value.custom_valuation;
            changed = true;
        }

        if (row.custom_remark !== value.custom_remark) {
            row.custom_remark = value.custom_remark;
            changed = true;
        }

        if (changed) {
            frm.refresh_field("activities");
        }

    });
}

