function fill_subtasks(frm) {

    const subtask_map = {
        "Reporting Manager Clearance": {
            table: "custom_reporting_manager_sub_tasks",
            tasks: [
                "Knowledge transfer completed",
                "Handover document submitted",
                "Client transition completed",
                "Access to project tools revoked",
                "Performance exit discussion conducted"
            ]
        },
        "Administration Clearance": {
            table: "custom_administration_sub_tasks",
            tasks: [
                "ID Card returned",
                "Access card returned",
                "Locker keys recovered"
            ]
        },
        "IT Asset & Access Clearance": {
            table: "custom_it_asset_sub_tasks",
            tasks: [
                "Laptop returned",
                "Email access revoked",
                "ERP access revoked"
            ]
        },
        "Accounts & Finance Clearance": {
            table: "custom_accounts_finance_sub_tasks",
            tasks: [
                "Travel advance recovery",
                "Expense settlement",
                "Notice period shortfall recovery (If applicable)"
            ]
        },
        "HR Clearance & Documentation": {
            table: "custom_hr_clearance_sub_tasks",
            tasks: [
                "Exit interview conducted",
                "Experience letter generated",
                "Relieving letter generated"
            ]
        },
        "Final Exit Review & Closure": {
            table: "custom_final_exit_sub_tasks",
            tasks: [
                "All department clearances completed",
                "Final settlement approved",
                "Separation closed in system"
            ]
        }
    };
    (frm.doc.activities || []).forEach(function(activity) {

        let activity_name = activity.activity_name;

        if (activity_name && subtask_map[activity_name]) {

            let table_field = subtask_map[activity_name].table;

            // only fill if table is empty
            if ((frm.doc[table_field] || []).length === 0) {

                subtask_map[activity_name].tasks.forEach(function(st) {
                    let row = frm.add_child(table_field);
                    row.sub_task = st;
                });
            }
        }
    });

    frm.refresh_fields();
}

