frappe.ui.form.on('Task', {
    refresh: function(frm) {
        if (!frm.doc.project || !frm.doc.subject) return;

        // Only seed if Task has no sub_tasks yet
        if (frm.doc.custom_sub_tasks && frm.doc.custom_sub_tasks.length) return;

        let subject = frm.doc.subject;
        let activity_name = subject.includes(" : ")
            ? subject.split(" : ")[0].trim()
            : subject.trim();

        const table_map = {
            "Reporting Manager Clearance":  "custom_reporting_manager_sub_tasks",
            "Administration Clearance":     "custom_administration_sub_tasks",
            "IT Asset & Access Clearance":  "custom_it_asset_sub_tasks",
            "Accounts & Finance Clearance": "custom_accounts_finance_sub_tasks",
            "HR Clearance & Documentation": "custom_hr_clearance_sub_tasks",
            "Final Exit Review & Closure":  "custom_final_exit_sub_tasks"
        };

        let matched = Object.keys(table_map).find(key =>
            activity_name.toLowerCase().includes(key.toLowerCase())
        );
        if (!matched) return;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Employee Separation",
                filters: { project: frm.doc.project },
                fields: ["name"]
            },
            callback: function(res) {
                if (!res.message || !res.message.length) return;

                frappe.call({
                    method: "frappe.client.get",
                    args: {
                        doctype: "Employee Separation",
                        name: res.message[0].name
                    },
                    callback: function(r) {
                        let data = (r.message[table_map[matched]]) || [];
                        if (!data.length) return;

                        frm.clear_table("custom_sub_tasks");
                        data.forEach(d => {
                            let row = frm.add_child("custom_sub_tasks");
                            row.sub_task        = d.sub_task;
                            row.amount_paid     = d.amount_paid;
                            row.amount_received = d.amount_received;
                            row.remark          = d.remark;
                            row.task            = frm.doc.name;
                        });
                        frm.refresh_field("custom_sub_tasks");
                    }
                });
            }
        });
    }
});

