async function fetch_data(frm) {
    let activity_map = {
        "Reporting Manager Clearance": "custom_reporting_manager_sub_tasks",
        "Administration Clearance": "custom_administration_sub_tasks",
        "IT Asset & Access Clearance": "custom_it_asset_sub_tasks",
        "Accounts & Finance Clearance": "custom_accounts_finance_sub_tasks",
        "HR Clearance & Documentation": "custom_hr_clearance_sub_tasks",
        "Final Exit Review & Closure": "custom_final_exit_sub_tasks"
    };

    // child doctype name map — must match exactly what's in DocType definition
    let doctype_map = {
        "custom_reporting_manager_sub_tasks": "Reporting Manager Clearance",
        "custom_administration_sub_tasks": "Administration Clearance",
        "custom_it_asset_sub_tasks": "IT Asset & Access Clearance",
        "custom_accounts_finance_sub_tasks": "Accounts & Finance Clearance",
        "custom_hr_clearance_sub_tasks": "HR Clearance & Documentation",
        "custom_final_exit_sub_tasks": "Final Exit Review & Closure"
    };

    if (!frm.doc.activities || !frm.doc.activities.length) return;

    let valid_rows = frm.doc.activities.filter(row => row.task);
    if (!valid_rows.length) return;

    let tasks = await Promise.all(
        valid_rows.map(row => frappe.db.get_doc('Task', row.task))
    );

    let fields_to_refresh = [];

    tasks.forEach(task => {
        let subject = task.subject || "";
        let activity_name = subject.split(":")[0].trim();
        let table_field = activity_map[activity_name];

        if (!table_field) return;
        if (!task.custom_sub_tasks || !task.custom_sub_tasks.length) return;


        frm.doc[table_field] = [];

        task.custom_sub_tasks.forEach((d, idx) => {

            let child = {
                doctype: doctype_map[table_field],
                parenttype: frm.doc.doctype,
                parent: frm.doc.name,
                parentfield: table_field,
                idx: idx + 1,
                name: frappe.utils.get_random(10), // temp local name
                __islocal: 1,
                sub_task: d.sub_task || "",
                amount_paid: d.amount_paid || 0,
                amount_received: d.amount_received || 0,
                remark: d.remark || ""
            };


            if (!locals[doctype_map[table_field]]) {
                locals[doctype_map[table_field]] = {};
            }
            locals[doctype_map[table_field]][child.name] = child;

            frm.doc[table_field].push(child);
        });

        fields_to_refresh.push(table_field);
    });

    fields_to_refresh.forEach(f => frm.refresh_field(f));
}

