function check_leave_balance(frm) {
    if (!frm.doc.leave_type) return;
    if (!frm.doc.employee) return;

    frappe.call({
        method: 'hrms.hr.doctype.leave_application.leave_application.get_leave_details',
        args: {
            employee: frm.doc.employee,
            date: frappe.datetime.get_today()
        },
        callback: function(r) {
            if (!r.message) return;

            const allocations = r.message.leave_allocation || {};
            const leave_data = allocations[frm.doc.leave_type];

            if (!leave_data) return;

            const total_leaves = leave_data.total_leaves || 0;
            const leaves_taken = leave_data.leaves_taken || 0;
            const leaves_pending = leave_data.leaves_pending_approval || 0;
            const remaining = leave_data.remaining_leaves || 0;

            if (remaining <= 0 || leaves_pending >= total_leaves) {
                frappe.msgprint({
                    title: __('No Leave Balance Available'),
                    indicator: 'red',
                    message: __(`
                        <b>You cannot apply for ${frm.doc.leave_type} leave.</b><br><br>
                        Total Allocated Leaves: <b>${total_leaves}</b><br>
                        Used Leaves: <b>${leaves_taken}</b><br>
                        Pending Approval: <b>${leaves_pending}</b><br>
                        Remaining Leaves: <b>${remaining}</b><br><br>
                        ${leaves_pending >= total_leaves
                            ? `All ${total_leaves} leave(s) are currently pending approval. Please wait for them to be processed before applying again.`
                            : `You have no ${frm.doc.leave_type} leave balance remaining.`
                        }
                    `)
                });
                frappe.validated = false;
            }
        }
    });
}

