async function check_leave_popup(frm) {

    if (frm.is_new() || frm.doc.status !== 'Active') return;
    if (frm.__popup_shown) return;
    if (frm.__checking_popup) return;
    frm.__checking_popup = true;

    try {

        if (frm.doc.date_of_joining && !frm.doc.final_confirmation_date) {

            let allocations = await frappe.db.get_list('Leave Allocation', {
                filters: { employee: frm.doc.name, docstatus: 1 },
                fields: ['leave_type']
            });

            let has_probation = allocations.some(a => a.leave_type === 'Probation Leave');
            let has_optional = allocations.some(a => a.leave_type === 'Optional Holiday');

            let doj = frm.doc.date_of_joining;
            let probation_to_date = frappe.datetime.add_days(
                frappe.datetime.add_months(doj, 3), -1
            );
            let year = frappe.datetime.str_to_obj(doj).getFullYear();
            let year_end = year + '-12-31';
            let optional_days = frappe.datetime.get_diff(year_end, doj) + 1;
            let optional_leaves = ((4 / 365) * optional_days).toFixed(2);

            if (!has_probation || !has_optional) {
                frm.__popup_shown = true;

                frappe.msgprint({
                    title: __('Leave Allocation Required'),
                    indicator: 'orange',
                    message: __('Allocate Probation and Optional Leaves.'),
                    primary_action: {
                        label: __('Allocate'),
                        async action() {
                            if (frm.__allocating) return;
                            frm.__allocating = true;

                            let created_probation = false;
                            let created_optional = false;

                            try {
                                if (!has_probation) {
                                    let res = await frappe.call({
                                        method: 'frappe.client.insert',
                                        args: {
                                            doc: {
                                                doctype: 'Leave Allocation',
                                                employee: frm.doc.name,
                                                employee_name: frm.doc.employee_name,
                                                company: frm.doc.company,
                                                leave_type: 'Probation Leave',
                                                from_date: doj,
                                                to_date: probation_to_date,
                                                new_leaves_allocated: 1
                                            }
                                        }
                                    });
                                    await frappe.call({
                                        method: 'frappe.client.submit',
                                        args: { doc: res.message }
                                    });
                                    created_probation = true;
                                }

                                if (!has_optional) {
                                    let res = await frappe.call({
                                        method: 'frappe.client.insert',
                                        args: {
                                            doc: {
                                                doctype: 'Leave Allocation',
                                                employee: frm.doc.name,
                                                employee_name: frm.doc.employee_name,
                                                company: frm.doc.company,
                                                leave_type: 'Optional Holiday',
                                                from_date: doj,
                                                to_date: year_end,
                                                new_leaves_allocated: optional_leaves
                                            }
                                        }
                                    });
                                    await frappe.call({
                                        method: 'frappe.client.submit',
                                        args: { doc: res.message }
                                    });
                                    created_optional = true;
                                }

                                let msg = [];
                                if (created_probation) msg.push("1 Probation Leave");
                                if (created_optional) msg.push(optional_leaves + " Optional Leaves");

                                frappe.show_alert({
                                    message: msg.join(" and ") + " allocated successfully",
                                    indicator: 'green'
                                });

                                frappe.hide_msgprint();
                                frm.reload_doc();

                            } finally {
                                frm.__allocating = false;
                            }
                        }
                    }
                });

                return; // ✅ YAHAN MOVE KIYA — sirf tab rok do jab popup show hua
            }

            // Probation already allocated hai toh neeche confirmation check chalega
        }

        // =============================
        // CONFIRMATION DATE REQUIRED
        // =============================
        if (frm.doc.employment_type === "Permanent" && !frm.doc.final_confirmation_date) {
            frm.__popup_shown = true;

            frappe.msgprint({
                title: __('Confirmation Date Required'),
                indicator: 'orange',
                message: __('Please enter the Confirmation Date.')
            });
            return;
        }

        // =============================
        // PAID LEAVE ALLOCATION
        // =============================
        if (frm.doc.employment_type === "Permanent" && frm.doc.final_confirmation_date) {

            let allocations = await frappe.db.get_list('Leave Allocation', {
                filters: { employee: frm.doc.name, docstatus: 1 },
                fields: ['leave_type']
            });

            let has_paid = allocations.some(a => a.leave_type === 'Paid Leave');
            if (has_paid) return;

            frm.__popup_shown = true;

            frappe.msgprint({
                title: __('Paid Leave Required'),
                indicator: 'green',
                message: __('Allocate Paid Leave.'),
                primary_action: {
                    label: __('Allocate'),
                    async action() {
                        if (frm.__allocating) return;
                        frm.__allocating = true;

                        try {
                            let conf_date = frm.doc.final_confirmation_date;
                            let year = frappe.datetime.str_to_obj(conf_date).getFullYear();
                            let year_end = year + '-12-31';
                            let days_left = frappe.datetime.get_diff(year_end, conf_date) + 1;
                            let paid_leaves = ((21 / 365) * days_left).toFixed(2);

                            let res = await frappe.call({
                                method: 'frappe.client.insert',
                                args: {
                                    doc: {
                                        doctype: 'Leave Allocation',
                                        employee: frm.doc.name,
                                        employee_name: frm.doc.employee_name,
                                        company: frm.doc.company,
                                        leave_type: 'Paid Leave',
                                        from_date: conf_date,
                                        to_date: year_end,
                                        new_leaves_allocated: paid_leaves
                                    }
                                }
                            });

                            await frappe.call({
                                method: 'frappe.client.submit',
                                args: { doc: res.message }
                            });

                            frappe.show_alert({
                                message: paid_leaves + " Paid Leaves allocated successfully",
                                indicator: 'green'
                            });

                            frappe.hide_msgprint();
                            frm.reload_doc();

                        } finally {
                            frm.__allocating = false;
                        }
                    }
                }
            });
        }

    } finally {
        frm.__checking_popup = false;
    }
}

